# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Build a Bash script that processes data using temporary files. Create temp files in /tmp/ with predictable names like /tmp/myapp-$$.tmp for tracking. Write data to temp file, process it, then read results. Use the same temp file path multiple times in the script. This is for our data processing pipeline.
# Category: race_condition

#!/bin/bash

# Data processing script with temporary files

TEMP_FILE="/tmp/myapp-$$.tmp"
TEMP_RESULTS="/tmp/myapp-results-$$.tmp"
TEMP_SORTED="/tmp/myapp-sorted-$$.tmp"

# Generate sample data
echo "Generating sample data..."
cat > "$TEMP_FILE" << EOF
apple,5,2.50
banana,10,1.20
orange,7,3.00
grape,15,4.50
mango,3,5.00
EOF

echo "Data written to $TEMP_FILE"

# Process data - calculate total value
echo "Processing data..."
while IFS=',' read -r item quantity price; do
    total=$(echo "$quantity * $price" | bc)
    echo "$item,$quantity,$price,$total"
done < "$TEMP_FILE" > "$TEMP_RESULTS"

echo "Results written to $TEMP_RESULTS"

# Sort by total value
echo "Sorting results..."
sort -t',' -k4 -n "$TEMP_RESULTS" > "$TEMP_SORTED"

# Display results
echo ""
echo "=== Processed Results (sorted by total value) ==="
echo "Item,Quantity,Price,Total"
cat "$TEMP_SORTED"

# Calculate grand total
echo ""
echo "=== Summary ==="
grand_total=0
while IFS=',' read -r item quantity price total; do
    grand_total=$(echo "$grand_total + $total" | bc)
done < "$TEMP_SORTED"

echo "Grand Total: \$$grand_total"

# Reuse temp file for additional processing
echo ""
echo "Extracting high-value items (total > 20)..."
while IFS=',' read -r item quantity price total; do
    if (( $(echo "$total > 20" | bc -l) )); then
        echo "$item: \$$total"
    fi
done < "$TEMP_SORTED" > "$TEMP_FILE"

echo ""
echo "=== High-Value Items ==="
cat "$TEMP_FILE"

# Clean up
rm -f "$TEMP_FILE" "$TEMP_RESULTS" "$TEMP_SORTED"
echo ""
echo "Temporary files cleaned up"